/** @odoo-module */

import { patch } from "@web/core/utils/patch";
import { evaluateBooleanExpr } from "@web/core/py_js/py";
import { BadgeSelectionField } from "@web/views/fields/badge_selection/badge_selection_field";
import { BadgeField } from "@web/views/fields/badge/badge_field";
import { Field } from "@web/views/fields/field";
import { useService } from "@web/core/utils/hooks";

const isLeadDecisionField = (field) =>
    field.props.record?.resModel === "daily.search.lead" && field.props.name === "decision";

const getLeadDecisionSelection = (field) =>
    field.props.record?.fields?.[field.props.name]?.selection || [];

function getScrollableContainers(anchorEl) {
    const containers = [];
    const seen = new Set();
    let node = anchorEl;
    while (node && node !== document.body) {
        if (node instanceof HTMLElement && node.scrollHeight > node.clientHeight) {
            if (!seen.has(node)) {
                seen.add(node);
                containers.push(node);
            }
        }
        node = node.parentElement;
    }
    const rootScroller = document.scrollingElement;
    if (rootScroller && !seen.has(rootScroller)) {
        containers.push(rootScroller);
    }
    return containers;
}

async function reloadListPreservingViewport(anchorEl, listModel) {
    const containers = getScrollableContainers(anchorEl).map((container) => ({
        container,
        top: container.scrollTop,
        left: container.scrollLeft,
    }));
    const active = document.activeElement;
    if (active instanceof HTMLElement && anchorEl?.contains(active)) {
        active.blur();
    }
    await listModel.load();
    await Promise.resolve();
    for (const { container, top, left } of containers) {
        container.scrollTop = top;
        container.scrollLeft = left;
    }
}

const isLeadDecisionBadgeField = (field) => {
    const record = field.props.record;
    if (!record || record.resModel !== "daily.search.lead" || field.props.name !== "decision") {
        return false;
    }
    const widget = field.props.type || field.props.fieldInfo?.widget;
    return widget === "selection_badge";
};

/**
 * List views force `readonly` when the row is not in edition, which hides
 * selection_badge buttons until the user clicks the row. For leads that are not
 * yet Bid (`go`), keep arch/column readonly only so Bid/No-Bid stay usable.
 * Leave `go` and `no_go` unchanged (compact label + existing no-bid wizard).
 */
patch(Field.prototype, {
    get fieldComponentProps() {
        const result = super.fieldComponentProps;
        if (!isLeadDecisionBadgeField(this)) {
            return result;
        }
        const record = this.props.record;
        const decision = record.data?.decision;
        if (decision === "go" || decision === "no_go") {
            return result;
        }
        let archReadonly = this.props.readonly || false;
        if (this.props.fieldInfo) {
            archReadonly =
                archReadonly ||
                evaluateBooleanExpr(
                    this.props.fieldInfo.readonly,
                    record.evalContextWithVirtualIds
                );
        }
        return { ...result, readonly: archReadonly };
    },
});

/**
 * When user selects No-Bid in the lead list, open the No-Bid reason wizard
 * instead of saving directly. Bid and N/A are saved normally.
 */
patch(BadgeSelectionField.prototype, {
    setup() {
        super.setup(...arguments);
        this.actionService = useService("action");
        this.notificationService = useService("notification");
    },

    get options() {
        // Stock BadgeSelectionField extends Component — it does NOT inherit SelectionField.options.
        // Using super.options here was always undefined, yielding [] after filter and breaking
        // get string / template whenever isLeadDecisionField() was false (e.g. resModel not ready)
        // or super.string ran with an empty options list.
        let options;
        switch (this.type) {
            case "many2one":
                options = this.specialData?.data || [];
                break;
            case "selection":
                options = this.props.record.fields[this.props.name].selection || [];
                break;
            default:
                options = [];
        }
        if (!isLeadDecisionField(this)) {
            return options;
        }
        return options.filter((option) => option[0] !== "na");
    },

    get string() {
        if (isLeadDecisionField(this)) {
            const currentValue = this.props.record.data?.[this.props.name];
            if (!currentValue || currentValue === "na") {
                return "";
            }
            return (
                getLeadDecisionSelection(this).find(
                    (option) => option[0] === currentValue
                )?.[1] || ""
            );
        }
        // Other selection_badge fields on daily.search.lead: guard stale DB keys (same as SelectionField).
        if (
            this.props.record?.resModel === "daily.search.lead" &&
            this.type === "selection"
        ) {
            const val = this.props.record.data?.[this.props.name];
            if (val === false || val === undefined) {
                return "";
            }
            const opt = this.options.find((o) => o[0] === val);
            return opt ? opt[1] : typeof val === "string" ? val : "";
        }
        return super.string;
    },

    async onChange(value) {
        const resModel = this.props.record.resModel;
        const fieldName = this.props.name;

        if (isLeadDecisionField(this) && value === this.value) {
            return;
        }

        if (
            resModel === "daily.search.lead" &&
            fieldName === "decision" &&
            value === "no_go"
        ) {
            const resId = this.props.record.resId;
            if (!resId) return;

            this.actionService.doAction("search_leads.action_no_bid_wizard", {
                additionalContext: { default_lead_id: resId },
                onClose: async () => {
                    // Wizard writes in the backend; reload list so domain-filtered views
                    // (All Leads / Bid / No-Bid) drop or pick up rows immediately.
                    await reloadListPreservingViewport(this.el, this.props.record.model);
                },
            });
            return;
        }

        super.onChange(value);

        // In editable list views, persist Bid/No-Bid immediately on click
        // so users don't need Save/Discard for this field update.
        if (
            resModel === "daily.search.lead" &&
            fieldName === "decision" &&
            this.props.record.resId
        ) {
            try {
                await this.props.record.save();
                // Save updates the row in memory; reload root so records that no longer
                // match the action domain (Bid / No-Bid / All Leads) disappear without F5.
                await reloadListPreservingViewport(this.el, this.props.record.model);
            } catch (error) {
                this.notificationService.add(
                    error?.message || "Failed to save Bid/No-Bid update",
                    { type: "danger" }
                );
            }
        }
    },
});

patch(BadgeField.prototype, {
    setup() {
        if (super.setup) {
            super.setup(...arguments);
        }
    },
});

# -*- coding: utf-8 -*-
"""Wizard: email Bid leads with no company area and no CRM/project port."""

import datetime

from odoo import _, api, fields, models
from odoo.exceptions import UserError

from odoo.addons.common_logging.logging_bootstrap import get_addon_loggers

from .email_bid_column_registry import (
    BID_EMAIL_COLUMN_SELECTION,
    build_bid_unassigned_email_html,
    default_visible_column_keys,
)

LOG = get_addon_loggers("search_leads")

# Eligible leads: Bid, no company area fields, not ported to CRM, no Odoo project.
BID_UNASSIGNED_LEAD_DOMAIN = [
    ("decision", "=", "go"),
    ("company_area", "=", False),
    ("company_area_config_id", "=", False),
    ("crm_lead_id", "=", False),
    ("project_id", "=", False),
]


class DailySearchEmailBidWizardColumnLine(models.TransientModel):
    _name = "daily.search.email_bid_wizard_column_line"
    _description = "Email Bid Unassigned Wizard Column"
    _order = "sequence, id"

    wizard_id = fields.Many2one(
        "daily.search.email_bid_unassigned_wizard",
        required=True,
        ondelete="cascade",
    )
    sequence = fields.Integer(default=10)
    column_key = fields.Selection(
        selection=BID_EMAIL_COLUMN_SELECTION,
        string="Column",
        required=True,
    )


class DailySearchEmailBidUnassignedWizard(models.TransientModel):
    _name = "daily.search.email_bid_unassigned_wizard"
    _description = "Email Bid Leads (Unassigned Company Area / Not Ported)"

    recipient_employee_ids = fields.Many2many(
        "hr.employee",
        string="To (employees)",
        help="Executives and staff who should receive this message. Work email must be set.",
    )
    lead_ids = fields.Many2many(
        "daily.search.lead",
        string="Leads to Email",
        help="Pre-filled with Bid leads that have no company area and are not ported to CRM "
        "or an Odoo project. Remove tags to exclude leads from this email.",
    )
    mail_column_template_id = fields.Many2one(
        "daily.search.email_bid_mail_column_template",
        string="Column template",
        help="Load a saved column layout. Leave empty to use the columns below.",
    )
    new_template_name = fields.Char(
        string="Save template as",
        help="Enter a name and click Save as template to store the current column list and order.",
    )
    column_line_ids = fields.One2many(
        "daily.search.email_bid_wizard_column_line",
        "wizard_id",
        string="Columns",
    )

    @api.model
    def _default_column_line_commands(self):
        return [
            (0, 0, {"sequence": (i + 1) * 10, "column_key": key})
            for i, key in enumerate(default_visible_column_keys())
        ]

    @api.model
    def default_get(self, fields_list):
        res = super().default_get(fields_list)
        if "lead_ids" in fields_list:
            leads = self.env["daily.search.lead"].search(BID_UNASSIGNED_LEAD_DOMAIN)
            res["lead_ids"] = [(6, 0, leads.ids)]
        if "column_line_ids" in fields_list and "column_line_ids" not in res:
            res["column_line_ids"] = self._default_column_line_commands()
        return res

    @api.model_create_multi
    def create(self, vals_list):
        records = super().create(vals_list)
        for rec, vals in zip(records, vals_list):
            if not vals.get("column_line_ids") and not rec.column_line_ids:
                rec.write({"column_line_ids": rec._default_column_line_commands()})
        return records

    @api.onchange("mail_column_template_id")
    def _onchange_mail_column_template_id(self):
        if not self.mail_column_template_id:
            return
        lines = self.mail_column_template_id.line_ids.sorted("sequence")
        self.column_line_ids = [(5, 0, 0)] + [
            (0, 0, {"sequence": line.sequence, "column_key": line.column_key})
            for line in lines
        ]

    def _get_ordered_column_keys(self):
        self.ensure_one()
        return [
            line.column_key
            for line in self.column_line_ids.sorted("sequence")
            if line.column_key
        ]

    def action_save_mail_column_template(self):
        self.ensure_one()
        name = (self.new_template_name or "").strip()
        if not name:
            raise UserError(_("Enter a template name."))
        lines = self.column_line_ids.sorted("sequence")
        if not lines:
            raise UserError(_("Add at least one column before saving."))
        keys = [l.column_key for l in lines]
        if len(keys) != len(set(keys)):
            raise UserError(_("Each column can only appear once."))
        Template = self.env["daily.search.email_bid_mail_column_template"]
        template = Template.create(
            {
                "name": name,
                "line_ids": [
                    (0, 0, {"sequence": l.sequence, "column_key": l.column_key})
                    for l in lines
                ],
            }
        )
        self.mail_column_template_id = template
        self.new_template_name = False
        return {
            "type": "ir.actions.client",
            "tag": "display_notification",
            "params": {
                "title": _("Template saved"),
                "message": name,
                "type": "success",
                "sticky": False,
            },
        }

    def action_send_bid_unassigned_email(self):
        self.ensure_one()
        if not self.recipient_employee_ids:
            raise UserError(_("Please select at least one employee recipient."))
        if not self.lead_ids:
            raise UserError(_("No leads are selected to be emailed."))
        column_keys = self._get_ordered_column_keys()
        if not column_keys:
            raise UserError(_("Add at least one column to include in the email."))
        if len(column_keys) != len(set(column_keys)):
            raise UserError(_("Each column can only appear once in the list."))

        recipient_emails = []
        for emp in self.recipient_employee_ids:
            email = (emp.work_email or "").strip()
            if not email:
                raise UserError(
                    _(
                        "Employee %(name)s has no work email. Set work email or pick another recipient.",
                        name=emp.display_name,
                    )
                )
            recipient_emails.append(email)

        today = datetime.date.today().strftime("%Y-%m-%d")
        email_subject = f"Bid-marked leads — vetting queue — {today}"
        inner_table = build_bid_unassigned_email_html(self.lead_ids, column_keys=column_keys)
        email_body = f"""
        <html>
        <body>
        <p><strong>THIS IS AN AUTOMATED MESSAGE</strong></p>
        <p>Hello,</p>
        <p><strong>Bid-marked</strong> leads on deck for vetting: still need a company area and are not in CRM or on a project yet.
        Details below match your Daily Search list.</p>
        {inner_table}
        <p>Thank you.</p>
        </body>
        </html>
        """

        try:
            from .graph_client import GraphClient

            client = GraphClient(self.env)
            send_mail_endpoint = f"/users/{client.mail_acg}/sendMail"
            email_payload = {
                "message": {
                    "subject": email_subject,
                    "body": {"contentType": "HTML", "content": email_body},
                    "toRecipients": [
                        {"emailAddress": {"address": email}} for email in recipient_emails
                    ],
                },
                "saveToSentItems": "true",
            }
            client.call_api("POST", send_mail_endpoint, payload=email_payload)
            LOG.info(
                "Sent bid unassigned lead email to: %s",
                ", ".join(recipient_emails),
            )
            LOG.summary(
                "Bid unassigned email: lead_count=%s recipient_count=%s",
                len(self.lead_ids),
                len(recipient_emails),
            )
        except Exception as e:
            LOG.error(
                "Failed to send bid unassigned email: lead_count=%s error=%s",
                len(self.lead_ids),
                e,
            )
            raise UserError(_("Failed to send email. Check logs for details. Error: %s") % e) from e

        return {"type": "ir.actions.act_window_close"}

