from odoo import http
from odoo.http import request
from odoo.addons.portal.controllers.portal import CustomerPortal, pager as portal_pager
from odoo.exceptions import AccessError, MissingError
from odoo.tools.translate import _


class ApplicantPortal(CustomerPortal):

    def _prepare_home_portal_values(self, counters):
        values = super()._prepare_home_portal_values(counters)
        if 'applicant_count' in counters:
            applicant_count = request.env['hr.applicant'].search_count([
                ('partner_id', '=', request.env.user.partner_id.id)
            ]) if request.env.user.partner_id else 0
            values['applicant_count'] = applicant_count
        return values

    @http.route(['/my/applications', '/my/applications/page/<int:page>'], type='http', auth="user", website=True)
    def portal_my_applications(self, page=1, sortby=None, filterby=None, **kw):
        Applicant = request.env['hr.applicant']

        domain = []
        if request.env.user.partner_id:
            domain = [('partner_id', '=', request.env.user.partner_id.id)]

        searchbar_sortings = {
            'date': {'label': _('Newest'), 'order': 'create_date desc'},
            'name': {'label': _('Name'), 'order': 'partner_name'},
            'job': {'label': _('Job Position'), 'order': 'job_id'},
            'stage': {'label': _('Stage'), 'order': 'stage_id'},
        }
        if not sortby:
            sortby = 'date'
        order = searchbar_sortings[sortby]['order']

        applicant_count = Applicant.search_count(domain)

        pager = portal_pager(
            url="/my/applications",
            total=applicant_count,
            page=page,
            step=self._items_per_page,
            url_args={'sortby': sortby, 'filterby': filterby},
        )

        applicants = Applicant.search(domain, order=order, limit=self._items_per_page, offset=pager['offset'])
        request.session['my_applications_history'] = applicants.ids[:100]

        values = {
            'applicants': applicants,
            'page_name': 'application',
            'pager': pager,
            'default_url': '/my/applications',
            'searchbar_sortings': searchbar_sortings,
            'sortby': sortby,
        }
        return request.render("hr_recruitment_enhanced.portal_my_applications", values)

    @http.route(['/my/application/<int:applicant_id>'], type='http', auth="user", website=True)
    def portal_my_application_detail(self, applicant_id, **kw):
        try:
            applicant = request.env['hr.applicant'].browse(applicant_id)

            # Check access
            if not applicant.exists() or applicant.partner_id != request.env.user.partner_id:
                raise AccessError(_("You don't have access to this application"))

            values = {
                'applicant': applicant,
                'page_name': 'application',
            }
            return request.render("hr_recruitment_enhanced.portal_my_application_detail", values)
        except (AccessError, MissingError):
            return request.redirect('/my')

    @http.route(['/my/application/<int:applicant_id>/upload'], type='http', auth="user", methods=['POST'], website=True, csrf=True)
    def portal_my_application_upload(self, applicant_id, **post):
        try:
            applicant = request.env['hr.applicant'].browse(applicant_id)

            # Check access - SECURITY: Only allow applicant to access their own application
            if not applicant.exists() or applicant.partner_id != request.env.user.partner_id:
                raise AccessError(_("You don't have access to this application"))

            # Handle file upload
            if 'document' in request.httprequest.files:
                uploaded_file = request.httprequest.files['document']
                if uploaded_file.filename:
                    # SECURITY: Only allow PDF files
                    filename_lower = uploaded_file.filename.lower()
                    if not filename_lower.endswith('.pdf'):
                        return request.redirect('/my/application/%s?upload=error&msg=only_pdf' % applicant_id)

                    import base64
                    file_content = uploaded_file.read()

                    # SECURITY: Check file size (max 10MB)
                    max_size = 10 * 1024 * 1024  # 10MB
                    if len(file_content) > max_size:
                        return request.redirect('/my/application/%s?upload=error&msg=file_too_large' % applicant_id)

                    # SECURITY: Validate PDF magic number
                    if not file_content.startswith(b'%PDF'):
                        return request.redirect('/my/application/%s?upload=error&msg=invalid_pdf' % applicant_id)

                    attachment = request.env['ir.attachment'].sudo().create({
                        'name': uploaded_file.filename,
                        'datas': base64.b64encode(file_content),
                        'res_model': 'hr.applicant',
                        'res_id': applicant.id,
                        'public': False,
                    })

                    # Post message in chatter
                    applicant.sudo().message_post(
                        body=_('Document uploaded by applicant: %s') % uploaded_file.filename,
                        attachment_ids=[attachment.id],
                    )

            return request.redirect('/my/application/%s?upload=success' % applicant_id)
        except (AccessError, MissingError):
            return request.redirect('/my')

