@api.depends('candidate_id', 'meeting_type', 'position_text', 'start_datetime')
def _compute_event_title(self):
    for record in self:
        if record.meeting_type == 'In Person':
            location_icon = '🏢 In Person'
        elif record.meeting_type == 'Teams':
            location_icon = '💻 Teams'
        else:
            location_icon = '📅 Teams'

        # Get time for display
        time_str = ''
        if record.start_datetime:
            local_dt = record._convert_from_utc(record.start_datetime)
            time_str = local_dt.strftime('%H:%M')

        # Use only first name for more compact display
        if record.candidate_id and record.candidate_id.name:
            candidate_part = record.candidate_id.name.upper()
        else:
            candidate_part = 'CANDIDATE'

        # Get position
        position_part = record.position_text.upper() if record.position_text else ''

        # Format: TIME ICON NAME | POSITION
        if position_part:
            record.event_title = f"{time_str} {location_icon} {candidate_part} | {position_part}"
        else:
            record.event_title = f"{time_str} {location_icon} {candidate_part}"

@api.depends('start_datetime', 'duration')
def _compute_end_datetime(self):
    for record in self:
        if record.start_datetime and record.duration:
            duration_hours = float(record.duration)
            record.end_datetime = record.start_datetime + datetime.timedelta(hours=duration_hours)
        else:
            record.end_datetime = False

@api.depends('status', 'meeting_type')
def _compute_calendar_color(self):
    """Yellow (3) when cancelled; otherwise 0/1 by meeting_type to match original default calendar colors."""
    for record in self:
        if record.status == 'cancelled':
            record.calendar_color = 3  # yellow in default palette
        elif record.meeting_type == 'Teams':
            record.calendar_color = 0  # same as original color="meeting_type" first value
        elif record.meeting_type == 'In Person':
            record.calendar_color = 1  # same as original color="meeting_type" second value
        else:
            record.calendar_color = 0

