@api.model
def _use_delegated_group_calendar(self):
    """
    True if events should be created on the HR group calendar using a delegated token.
    Requires: recruitment.use_delegated_group_calendar=True, recruitment.group_id set,
    and either recruitment.delegated_refresh_token (from Connect) or
    recruitment.delegated_user_email + recruitment.delegated_user_password (ROPC).
    """
    ICPSudo = self.env['ir.config_parameter'].sudo()
    use = (ICPSudo.get_param('recruitment.use_delegated_group_calendar') or 'False').strip().lower() in ('true', '1', 'yes')
    if not use:
        return False
    group_id = (ICPSudo.get_param('recruitment.group_id') or '').strip()
    if not group_id:
        return False
    refresh_token = (ICPSudo.get_param('recruitment.delegated_refresh_token') or '').strip()
    if refresh_token:
        return True
    email = (ICPSudo.get_param('recruitment.delegated_user_email') or '').strip()
    password = ICPSudo.get_param('recruitment.delegated_user_password') or ''
    return bool(email and password)

def _ensure_calendar_shared_with_hr(self, client, user_id):
    """
    Ensure the organizer's calendar is shared with the HR principal (recruitment.calendar_share_with_email)
    with write permission so anyone with HR access can edit interview events.
    Idempotent: lists existing permissions and only POSTs if the principal does not already have write.
    """
    ICPSudo = self.env['ir.config_parameter'].sudo()
    share_email = (ICPSudo.get_param('recruitment.calendar_share_with_email') or '').strip()
    if not share_email:
        return
    share_email_lower = share_email.lower()
    permissions_endpoint = f"/users/{user_id}/calendar/calendarPermissions"
    write_roles = ('write', 'readWrite', 'delegateWithoutPrivateEventAccess', 'delegateWithPrivateEventAccess')
    try:
        response = client.call_api('GET', permissions_endpoint)
        existing = response.get('value') or []
        for perm in existing:
            addr = (perm.get('emailAddress') or {}).get('address') or ''
            if addr.lower() == share_email_lower and (perm.get('role') or '').lower() in write_roles:
                _logger.debug("Calendar already shared with HR principal with write: %s", share_email)
                return
        body = {
            'emailAddress': {'name': 'HR (Recruitment)', 'address': share_email},
            'isInsideOrganization': True,
            'isRemovable': True,

def _get_graph_meeting_payload(self, is_online, location_display, email_subject, all_attendees, online_provider=None):
    """Build the JSON payload for Graph API event create/update (subject, start/end UTC, attendees, body)."""
    self.ensure_one()
    start_utc = self._convert_to_utc(self.start_datetime)
    end_utc = self._convert_to_utc(self.end_datetime)

    # Format as ISO 8601 with Z suffix for UTC
    start_time_iso = start_utc.strftime('%Y-%m-%dT%H:%M:%S.000Z')
    end_time_iso = end_utc.strftime('%Y-%m-%dT%H:%M:%S.000Z')

    meeting_payload = {
        'subject': email_subject,
        'start': {
            'dateTime': start_time_iso,
            'timeZone': 'UTC',
        },
        'end': {
            'dateTime': end_time_iso,
            'timeZone': 'UTC',
        },
        'attendees': all_attendees, 
        'isOnlineMeeting': is_online, 
        'location': {
            'displayName': location_display
        },
        'body': {
            'contentType': 'HTML',
            'content': f"<p>You are invited to an interview for the {self.position_text} position. A follow-up email contains the detailed instructions and attachments.</p>",
        },
    }

    if is_online and online_provider:
        meeting_payload['onlineMeetingProvider'] = online_provider

    return meeting_payload

def action_send_invite(self):
    """Create calendar event in Graph (user or group calendar), then send candidate and internal emails."""
    self.ensure_one()

    if self.status != 'draft':
        raise UserError(self.env._("The invite must be in 'Draft' status to be sent."))
    candidate_email_clean = (self.candidate_email or '').strip()
    if not candidate_email_clean:
        raise UserError(self.env._("The candidate must have an email address to send the invitation."))

    candidate_body_html, _, email_subject = self._get_email_templates()
    candidate_attendee = {
        'emailAddress': {'address': candidate_email_clean, 'name': self.candidate_id.name},
        'type': 'required'
    }
    internal_attendees = [{
        'emailAddress': {'address': att.work_email.strip(), 'name': att.name},
        'type': 'required'
    } for att in self.acg_attendees_ids if att.work_email]
    # recruiting@acglp.com (or recruitment.recruiting_email) is always included as attendee
    recruiting_email = self._get_recruiting_email()
    internal_attendees.append({
        'emailAddress': {'address': recruiting_email, 'name': 'Recruitment Team'},
        'type': 'optional'
    })
    group_email = self._get_recruitment_group_email()
    use_delegated_group = self._use_delegated_group_calendar()
    if group_email and not use_delegated_group:
        internal_attendees.append({
            'emailAddress': {'address': group_email.strip(), 'name': 'Recruitment Calendar (Group)'},
            'type': 'required'
        })
        _logger.info("Adding HR group as attendee (user calendar): %s", group_email)
    all_attendees = [candidate_attendee] + internal_attendees

    if self.meeting_type == 'Teams':
        is_online = True
        location_display = 'Microsoft Teams'
        online_provider = 'teamsForBusiness'
    elif self.meeting_type == 'In Person':
        is_online = False
        location_display = self.MEETING_LOCATION_IN_PERSON
        online_provider = None
    else:
        is_online = False
        location_display = self.meeting_type
        online_provider = None

    teams_link = None
    # Graph API: create event (either on group calendar with delegated token or on user calendar app-only).
    client = self._get_graph_client()
    if use_delegated_group:
        group_id = self._get_recruitment_group_id().strip()
        calendar_endpoint = f"/groups/{group_id}/calendar/events"
        meeting_payload = self._get_graph_meeting_payload(is_online, location_display, email_subject, all_attendees, online_provider)
        _logger.info("Creating event on HR group calendar (delegated): %s", calendar_endpoint)
        try:
            api_response = client.call_api('POST', calendar_endpoint, meeting_payload, use_delegated=True)
            graph_event_id = api_response.get('id')
            if graph_event_id:
                self.write({
                    'microsoft_graph_event_id': graph_event_id,
                    'microsoft_graph_calendar_type': 'group',
                    'microsoft_graph_group_id': group_id,
                })
                _logger.info("Saved MS Graph Event ID (group calendar): %s", graph_event_id)
            if is_online:
                teams_link = api_response.get('onlineMeeting', {}).get('joinUrl')
                if teams_link:
                    self.write({'microsoft_graph_meeting_join_url': teams_link})
            self.message_post(
                body=self.env._("Calendar event created on HR group calendar (delegated). Meeting Type: %(type)s. Link: %(link)s")
                % {"type": self.meeting_type, "link": teams_link if is_online else "N/A"},
                subtype_xmlid="mail.mt_note",
            )
        except UserError:
            raise
        except Exception as e:
            _logger.error("Group calendar create failed: %s", e)
            raise UserError(self.env._("Failed to create event on HR group calendar. Check delegated user and app Group.ReadWrite.All (Delegated). Error: %(error)s") % {"error": e})
    else:
        user_id = client.mail_acg
        self._ensure_calendar_shared_with_hr(client, user_id)
        calendar_endpoint = self.CALENDAR_EVENT_ENDPOINT.format(user_id=user_id)
        meeting_payload = self._get_graph_meeting_payload(is_online, location_display, email_subject, all_attendees, online_provider)
        _logger.info("Creating calendar event on user calendar (app-only)")
        try:
            api_response = client.call_api('POST', calendar_endpoint, meeting_payload)
            graph_event_id = api_response.get('id')
            if graph_event_id:
                self.write({'microsoft_graph_event_id': graph_event_id})
                _logger.info(f"Saved MS Graph Event ID: {graph_event_id}")
            if is_online:
                teams_link = api_response.get('onlineMeeting', {}).get('joinUrl')
                if teams_link:
                    self.write({'microsoft_graph_meeting_join_url': teams_link})
            if is_online and not teams_link:
                raise UserError(
                    self.env._("Teams meeting URL not found in API response. The event may have been created without an online meeting link.")
                )
            self.message_post(
                body=self.env._("Calendar event created successfully. Meeting Type: %(type)s. Link: %(link)s")
                % {"type": self.meeting_type, "link": teams_link if teams_link else "N/A"},
                subtype_xmlid="mail.mt_note",
            )
            if group_email:
                self.message_post(body=self.env._("Event added to HR group calendar (6.0 HR invited). View in Outlook or in Teams: Calendar > add '6.0 HR' calendar."), subtype_xmlid='mail.mt_note')
        except UserError:
            raise
        except Exception as e:
            _logger.error(f"365 Calendar API Error: {e}")
            raise UserError(self.env._("Failed to create calendar event. Error: %(error)s") % {"error": e})

    # Graph sendMail: mailbox may differ from calendar organizer (mail_sender vs mail_acg on GraphClient).
    client = self._get_graph_client()
    mail_sender = client.mail_sender
    send_mail_endpoint = self.SEND_MAIL_ENDPOINT.format(user_id=mail_sender)

    if teams_link:
        candidate_email_content = candidate_body_html.replace(
            "TEAMS Link", 
            f"<a href='{teams_link}'>Join Microsoft Teams Meeting</a>"
        )
    else:
        candidate_email_content = candidate_body_html

    attachments_list = []

    if self.include_sow_rfi_test:
        try:
            file_name, file_content_b64 = self._read_local_file_data(self.FILE_SOW_RFI)
            attachments_list.append({
                '@odata.type': '#microsoft.graph.fileAttachment',
                'name': file_name,
                'contentType': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
                'contentBytes': file_content_b64
            })
            self.message_post(body=self.env._("Prepared attachment: %(name)s") % {"name": file_name}, subtype_xmlid="mail.mt_note")
        except UserError as e:
            self.message_post(body=self.env._("WARNING: SOW/RFI file preparation failed. Error: %(error)s") % {"error": e}, subtype_xmlid="mail.mt_note")

    if self.include_excel_test:
        try:
            file_name, file_content_b64 = self._read_local_file_data(self.FILE_EXCEL_TEST)
            attachments_list.append({
                '@odata.type': '#microsoft.graph.fileAttachment',
                'name': file_name,
                'contentType': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                'contentBytes': file_content_b64
            })
            self.message_post(body=self.env._("Prepared attachment: %(name)s") % {"name": file_name}, subtype_xmlid="mail.mt_note")
        except UserError as e:
            self.message_post(body=self.env._("WARNING: Excel file preparation failed. Error: %(error)s") % {"error": e}, subtype_xmlid="mail.mt_note")

    if self.include_employment_application:
        try:
            file_name, file_content_b64 = self._read_local_file_data(self.FILE_EMPLOYMENT_APP)
            attachments_list.append({
                '@odata.type': '#microsoft.graph.fileAttachment',
                'name': file_name,
                'contentType': 'application/pdf',
                'contentBytes': file_content_b64
            })
            self.message_post(body=self.env._("Prepared attachment: %(name)s") % {"name": file_name}, subtype_xmlid="mail.mt_note")

