        raise
    except Exception as e:
        _logger.error(f"365 Email API Error: {e}")
        raise UserError(self.env._("Failed to send invitation email. Error: %(error)s") % {"error": e})

    self.write({'status': 'sent'})

    return True

@api.model_create_multi
def create(self, vals_list):
    """Trigger next_interview_date recompute on applicant when interview is created."""
    records = super().create(vals_list)
    applicants = records.mapped('applicant_id').filtered(lambda a: a)
    if applicants:
        applicants._compute_next_interview_date()
    return records

def write(self, vals):
    """On save: if sync_fields changed and invite has a Graph event, push update to Graph (no resend)."""
    if self.env.context.get('skip_graph_sync'):
        return super().write(vals)

    # Only trigger sync when a field that affects the calendar event was changed
    # We also only sync if the event was already created in MS Graph
    sync_fields = ['start_datetime', 'duration', 'meeting_type', 'position_text', 'candidate_id', 'acg_attendees_ids']
    needs_sync = any(field in vals for field in sync_fields)

    res = super(RecruitmentInterviewInvite, self).write(vals)

    if needs_sync:
        for record in self:
            if record.microsoft_graph_event_id and record.status not in ['draft', 'cancelled']:
                try:
                    record._sync_update_to_graph()
                except Exception as e:
                    _logger.error(f"Failed to sync update to Graph API for record {record.id}: {e}")
                    record.message_post(body=record.env._("Failed to sync update to MS Graph Calendar. Error: %(error)s") % {"error": e}, subtype_xmlid="mail.mt_note")

    # Trigger next_interview_date recompute on applicant when interview is updated
    if any(field in vals for field in ['start_datetime', 'status', 'applicant_id']):
        applicants = self.mapped('applicant_id').filtered(lambda a: a)
        if applicants:
            applicants._compute_next_interview_date()

    return res

def unlink(self):
    """Before delete: cancel/delete the event in Graph if it exists, then remove the record."""
    # Store applicants before deletion to recompute next_interview_date
    applicants = self.mapped('applicant_id').filtered(lambda a: a)

    for record in self:
        if record.microsoft_graph_event_id or record.microsoft_graph_online_meeting_id:
            try:
                record._sync_delete_to_graph()
            except Exception as e:
                _logger.error(f"Failed to delete event/meeting from Graph API for record {record.id}: {e}")

    res = super().unlink()

    # Trigger next_interview_date recompute after deletion
    if applicants:
        applicants._compute_next_interview_date()

    return res

def _sync_update_to_graph(self):
    """PATCH the existing Graph event with current start, end, subject, location, and attendees (no new email)."""
    self.ensure_one()
    if not self.microsoft_graph_event_id:
        return

from odoo import http
from odoo.http import request


class QuizController(http.Controller):

    @http.route('/recruitment/quiz/<string:token>', type='http', auth='public', website=True)
    def quiz_form(self, token, **kwargs):
        applicant = request.env['hr.applicant'].sudo().search([('quiz_token', '=', token)], limit=1)

        if not applicant:
            return request.render('hr_recruitment_enhanced.quiz_invalid_token')

        if applicant.quiz_completed:
            return request.render('hr_recruitment_enhanced.quiz_already_completed')

        if not applicant.job_id or not applicant.job_id.quiz_question_ids:
            return request.render('hr_recruitment_enhanced.quiz_no_questions')

        questions = applicant.job_id.quiz_question_ids.sorted('sequence')

        return request.render('hr_recruitment_enhanced.quiz_template', {
            'applicant': applicant,
            'questions': questions,
            'token': token,
        })

    @http.route('/recruitment/quiz/<string:token>/submit', type='http', auth='public', methods=['POST'], csrf=False)
    def quiz_submit(self, token, **post):
        applicant = request.env['hr.applicant'].sudo().search([('quiz_token', '=', token)], limit=1)

        if not applicant or applicant.quiz_completed:
            return request.redirect('/recruitment/quiz/' + token)

        for key, value in post.items():
            if key.startswith('question_'):
                question_id = int(key.split('_')[1])
                question = request.env['hr.job.quiz.question'].sudo().browse(question_id)

                answer_vals = {
                    'applicant_id': applicant.id,
                    'question_id': question_id,
                }

                if question.question_type == 'multiple_choice':
                    answer_vals['selected_answer'] = value
                elif question.question_type == 'true_false':
                    answer_vals['true_false_answer'] = value
                elif question.question_type in ['short_answer', 'essay']:
                    answer_vals['text_answer'] = value

                request.env['hr.applicant.quiz.answer'].sudo().create(answer_vals)

        applicant.sudo().write({'quiz_completed': True})

        return request.render('hr_recruitment_enhanced.quiz_thank_you', {
            'applicant': applicant,
        })

