class HrApplicant(models.Model):
    _inherit = 'hr.applicant'

    phone_screen_answer_ids = fields.One2many(
        'hr.applicant.phone.screen.answer',
        'applicant_id',
        string='Phone Screen Answers'
    )

    quiz_answer_ids = fields.One2many(
        'hr.applicant.quiz.answer',
        'applicant_id',
        string='Quiz Answers'
    )

    checklist_item_ids = fields.One2many(
        'hr.applicant.checklist.item',
        'applicant_id',
        string='Recruitment Checklist'
    )

    quiz_token = fields.Char(
        string='Quiz Access Token',
        copy=False,
        readonly=True
    )

    quiz_completed = fields.Boolean(
        string='Quiz Completed',
        default=False
    )

    portal_user_id = fields.Many2one(
        'res.users',
        string='Portal User',
        help='Portal user account for this applicant',
        compute='_compute_portal_user_id',
        store=True
    )

    has_portal_access = fields.Boolean(
        string='Has Portal Access',
        compute='_compute_has_portal_access',
        store=True
    )

    @api.depends('partner_id.user_ids')
    def _compute_portal_user_id(self):
        for applicant in self:
            if applicant.partner_id:
                portal_user = applicant.partner_id.user_ids.filtered(
                    lambda u: u.has_group('base.group_portal') and not u.has_group('base.group_user')
                )
                applicant.portal_user_id = portal_user[:1] if portal_user else False
            else:
                applicant.portal_user_id = False

    @api.depends('portal_user_id')
    def _compute_has_portal_access(self):
        for applicant in self:
            applicant.has_portal_access = bool(applicant.portal_user_id)

    def action_populate_phone_screen_questions(self):
        """Ensure each applicant has one answer line per job question; only creates missing rows (never overwrites)."""
        Answer = self.env['hr.applicant.phone.screen.answer']
        for applicant in self:
            if not applicant.job_id or not applicant.job_id.phone_screen_question_ids:
                continue
            existing_questions = applicant.phone_screen_answer_ids.mapped('question_id')
            for question in applicant.job_id.phone_screen_question_ids:
                if question not in existing_questions:
                    Answer.create({
                        'applicant_id': applicant.id,
                        'question_id': question.id,
                    })

    def action_sync_quiz_questions(self):
        """Sync quiz questions with the job position. Adds new questions and removes answers for deleted questions."""
        self.ensure_one()

        if not self.job_id:
            return {
                'type': 'ir.actions.client',
                'tag': 'display_notification',
                'params': {
                    'title': 'No Job Position',
                    'message': 'Cannot sync quiz: No job position assigned to this applicant.',
                    'type': 'warning',
                }
            }

        job_questions = self.job_id.quiz_question_ids

        if not job_questions:
            return {
                'type': 'ir.actions.client',
                'tag': 'display_notification',
                'params': {
                    'title': 'No Quiz Questions',
                    'message': 'The job position has no quiz questions configured.',
                    'type': 'warning',
                }
            }

        QuizAnswer = self.env['hr.applicant.quiz.answer']
        existing_questions = self.quiz_answer_ids.mapped('question_id')

        added_count = 0
        for question in job_questions:
            if question not in existing_questions:
                QuizAnswer.create({
                    'applicant_id': self.id,
                    'question_id': question.id,
                })
                added_count += 1

        removed_count = 0
        for answer in self.quiz_answer_ids:
            if answer.question_id not in job_questions:
                answer.unlink()
                removed_count += 1

        message_parts = []
        if added_count > 0:
            message_parts.append(f'{added_count} new question(s) added')
        if removed_count > 0:
            message_parts.append(f'{removed_count} obsolete answer(s) removed')
        if not message_parts:
            message_parts.append('Quiz is already up to date')

        return {
            'type': 'ir.actions.client',
            'tag': 'display_notification',
            'params': {
                'title': 'Quiz Synced',
                'message': ', '.join(message_parts) + '.',
                'type': 'success',
            }
        }

    def action_print_phone_screen(self):
        self.ensure_one()
        return self.env.ref(
            'hr_recruitment_enhanced.hr_applicant_phone_screen_report_action'
        ).report_action(self)

    def action_populate_checklist_items(self):
        self.ensure_one()
        if not self.job_id or not self.job_id.checklist_template_ids:
            return

        existing_templates = self.checklist_item_ids.mapped('template_id')

        for template in self.job_id.checklist_template_ids:
            if template not in existing_templates:
                self.env['hr.applicant.checklist.item'].create({
                    'applicant_id': self.id,
                    'template_id': template.id,
                    'name': template.name,
                    'sequence': template.sequence,
                    'upload_by': template.upload_by,
                })

    def action_generate_quiz_link(self):
        self.ensure_one()
        if not self.quiz_token:
            self.quiz_token = secrets.token_urlsafe(32)

        base_url = self.env['ir.config_parameter'].sudo().get_param('web.base.url')
        quiz_url = f"{base_url}/recruitment/quiz/{self.quiz_token}"

        return {
            'type': 'ir.actions.client',
            'tag': 'display_notification',
            'params': {
                'title': 'Quiz Link Generated',
                'message': f'Quiz URL: {quiz_url}',
                'type': 'success',
                'sticky': True,
            }
        }

    def action_grant_portal_access(self):
        self.ensure_one()
        if not self.partner_id:
            self.partner_id = self.env['res.partner'].create({
                'name': self.partner_name,
                'email': self.email_from,
                'phone': self.partner_phone,
                'mobile': self.partner_mobile,
            })

        if not self.portal_user_id:
            wizard = self.env['portal.wizard'].with_context(
                active_ids=[self.partner_id.id]
            ).create({})
            for wizard_user in wizard.user_ids:
                wizard_user.action_grant_access()

            base_url = self.env['ir.config_parameter'].sudo().get_param('web.base.url')
            portal_url = f"{base_url}/my/applications"

            self.message_post(
                body=f"Portal access granted. Portal URL: {portal_url}",
                subject="Portal Access Granted"
            )

            return {
                'type': 'ir.actions.client',
                'tag': 'display_notification',
                'params': {
                    'title': 'Portal Access Granted',
                    'message': f'Portal access has been granted. URL: {portal_url}',
                    'type': 'success',
                    'sticky': True,
                }
            }
        else:
            return {
                'type': 'ir.actions.client',
                'tag': 'display_notification',
                'params': {
                    'title': 'Portal Access Already Exists',
                    'message': 'This applicant already has portal access.',
                    'type': 'warning',
                }
            }

    @api.model_create_multi
    def create(self, vals_list):
        applicants = super().create(vals_list)
        for applicant in applicants:
            if applicant.job_id:
                if applicant.job_id.phone_screen_question_ids:
                    applicant.action_populate_phone_screen_questions()
                if applicant.job_id.checklist_template_ids:
                    applicant.action_populate_checklist_items()
        return applicants

