        string="Days Position Open",
        compute="_compute_days_open",
        store=True,
        help="Number of days since manager requested the position"
    )

    days_to_close = fields.Integer(
        string="Days to Close",
        compute="_compute_days_to_close",
        store=True,
        help="Number of days from request to position closure"
    )

    @api.depends('name')
    def _compute_similar_jobs(self):
        for job in self:
            if job.name and len(job.name) > 3:
                similar = self.search([
                    ('name', 'ilike', job.name),
                    ('id', '!=', job.id)
                ], limit=5)
                job.similar_job_ids = similar
            else:
                job.similar_job_ids = False

    @api.model_create_multi
    def create(self, vals_list):
        # Auto-populate manager_request_date with today's date if not provided
        for vals in vals_list:
            if 'manager_request_date' not in vals:
                vals['manager_request_date'] = fields.Date.today()

        jobs = super().create(vals_list)
        for job in jobs:
            if job.recruitment_status == 'open':
                try:
                    self.env['hr.job.publication.history'].create({
                        'job_id': job.id,
                        'action': 'published',
                        'user_id': self.env.user.id,
                    })
                except Exception:
                    pass

            templates = self.env['hr.job.phone.screen.question'].search([
                ('is_template', '=', True),
                ('job_id', '=', False)
            ])
            # Many template lines would each trigger applicant sync; skip until all lines exist (usually zero applicants on brand-new job).
            Question = self.env['hr.job.phone.screen.question'].with_context(
                skip_phone_screen_applicant_sync=True
            )
            for template in templates:
                Question.create({
