                    'template_question_id': template.id,
                    'question': template.question,
                    'expected_answer': template.expected_answer,
                    'is_mandatory': template.is_mandatory,
                    'question_type': template.question_type,
                    'sequence': template.sequence,
                })

        return jobs

    def write(self, vals):
        if 'recruitment_status' in vals:
            for job in self:
                old_status = job.recruitment_status
                new_status = vals['recruitment_status']

                if old_status != new_status:
                    result = super(HrJob, job).write(vals)
                    try:
                        action = 'published' if new_status == 'open' else 'unpublished'
                        self.env['hr.job.publication.history'].create({
                            'job_id': job.id,
