from odoo import models, fields, api


class HrJob(models.Model):
    _inherit = 'hr.job'

    recruitment_status = fields.Selection(
        [('open', 'Open'), ('closed', 'Closed')],
        string='Recruitment Status',
        default='open',
        tracking=True,
        help="Indicates whether this position is actively recruiting"
    )

    publication_history_ids = fields.One2many(
        'hr.job.publication.history',
        'job_id',
        string='Publication History'
    )

    phone_screen_question_ids = fields.One2many(
        'hr.job.phone.screen.question',
        'job_id',
        string='Phone Screen Questions'
    )

    quiz_question_ids = fields.One2many(
        'hr.job.quiz.question',
        'job_id',
        string='Quiz Questions'
    )

    checklist_template_ids = fields.One2many(
        'hr.job.checklist.template',
        'job_id',
        string='Recruitment Checklist Templates'
    )

    similar_job_ids = fields.Many2many(
        'hr.job',
        compute='_compute_similar_jobs',
        string='Similar Positions'
    )

    sharepoint_url = fields.Char(
        string="SharePoint URL",
        help="Link to SharePoint folder for this position"
    )

    manager_request_date = fields.Date(
        string="Manager Request Date",
        help="Date when the hiring manager requested this position",
        tracking=True
    )

    days_position_open = fields.Integer(
        string="Days Position Open",
        compute="_compute_days_open",
        store=True,
        help="Number of days since manager requested the position"
    )

    days_to_close = fields.Integer(
        string="Days to Close",
        compute="_compute_days_to_close",
        store=True,
        help="Number of days from request to position closure"
    )

    @api.depends('name')
    def _compute_similar_jobs(self):
        for job in self:
            if job.name and len(job.name) > 3:
                similar = self.search([
                    ('name', 'ilike', job.name),
                    ('id', '!=', job.id)
                ], limit=5)
                job.similar_job_ids = similar
            else:
                job.similar_job_ids = False

    @api.model_create_multi
    def create(self, vals_list):
        # Auto-populate manager_request_date with today's date if not provided
        for vals in vals_list:
            if 'manager_request_date' not in vals:
                vals['manager_request_date'] = fields.Date.today()

        jobs = super().create(vals_list)
        for job in jobs:
            if job.recruitment_status == 'open':
                try:
                    self.env['hr.job.publication.history'].create({
                        'job_id': job.id,
                        'action': 'published',
                        'user_id': self.env.user.id,
                    })
                except Exception:
                    pass

            templates = self.env['hr.job.phone.screen.question'].search([
                ('is_template', '=', True),
                ('job_id', '=', False)
            ])
            # Many template lines would each trigger applicant sync; skip until all lines exist (usually zero applicants on brand-new job).
            Question = self.env['hr.job.phone.screen.question'].with_context(
                skip_phone_screen_applicant_sync=True
            )
            for template in templates:
                Question.create({
                    'job_id': job.id,
                    'template_question_id': template.id,
                    'question': template.question,
                    'expected_answer': template.expected_answer,
                    'is_mandatory': template.is_mandatory,
                    'question_type': template.question_type,
                    'sequence': template.sequence,
                })

        return jobs

    def write(self, vals):
        if 'recruitment_status' in vals:
            for job in self:
                old_status = job.recruitment_status
                new_status = vals['recruitment_status']

                if old_status != new_status:
                    result = super(HrJob, job).write(vals)
                    try:
                        action = 'published' if new_status == 'open' else 'unpublished'
                        self.env['hr.job.publication.history'].create({
                            'job_id': job.id,
                            'action': action,
                            'user_id': self.env.user.id,
                        })
                    except Exception:
                        pass
                    return result

        return super().write(vals)

    @api.depends('manager_request_date')
    def _compute_days_open(self):
        for job in self:
            if job.manager_request_date:
                delta = fields.Date.today() - job.manager_request_date
                job.days_position_open = delta.days
            else:
                job.days_position_open = 0

    @api.depends('manager_request_date')
    def _compute_days_to_close(self):
        for job in self:
            if job.manager_request_date:
                delta = fields.Date.today() - job.manager_request_date
                job.days_to_close = delta.days
            else:
                job.days_to_close = 0

    def _sync_applicant_phone_screen_answers(self):
        """Add missing phone screen answer lines for all applicants on these job(s)."""
        applicants = self.env['hr.applicant'].search([('job_id', 'in', self.ids)])
        applicants.action_populate_phone_screen_questions()

    def action_sync_phone_screen_to_applicants(self):
        self.ensure_one()
        applicants = self.env['hr.applicant'].search([('job_id', '=', self.id)])
        count = len(applicants)
        self._sync_applicant_phone_screen_answers()
        return {
            'type': 'ir.actions.client',
            'tag': 'display_notification',
            'params': {
                'title': 'Phone Screen Synced',
                'message': f'Phone screen questions synced to {count} applicant(s).',
                'type': 'success',
                'sticky': False,
            }
        }

    def action_open_position_wizard(self):
        self.ensure_one()
        return {
            'name': 'Open Position',
            'type': 'ir.actions.act_window',
            'res_model': 'hr.job.open.position.wizard',
            'view_mode': 'form',
            'target': 'new',
            'context': {
                'default_job_id': self.id,
            }
        }

    def action_sync_employee_positions_to_recruitment(self):
        jobs_with_employees = self.search([
            ('employee_ids', '!=', False),
            ('recruitment_status', '!=', 'closed')
        ])

        if not jobs_with_employees:
            return {
                'type': 'ir.actions.client',
                'tag': 'display_notification',
                'params': {
                    'title': 'No Jobs to Sync',
                    'message': 'All job positions with employees are already set to closed status.',
                    'type': 'info',
                    'sticky': False,
                }
            }

        synced_count = 0
        for job in jobs_with_employees:
            job.write({
                'recruitment_status': 'closed',
                'no_of_recruitment': 0,
            })
            synced_count += 1

        return {
            'type': 'ir.actions.client',
            'tag': 'display_notification',
            'params': {
                'title': 'Sync Complete',
                'message': f'Successfully synced {synced_count} job position(s) with closed recruitment status.',
                'type': 'success',
                'sticky': False,
            }
        }

    def action_populate_default_checklist(self):
        self.ensure_one()

        default_checklist_items = [
            {'sequence': 1, 'name': 'Job Posting Template'},
            {'sequence': 2, 'name': 'Resume Filter Checklist'},
            {'sequence': 3, 'name': 'Phone Screen Questions'},
            {'sequence': 4, 'name': 'Interview Scorecard'},
            {'sequence': 5, 'name': 'Skills Test and Rubric'},
            {'sequence': 6, 'name': 'Job Description'},
            {'sequence': 7, 'name': 'Main Activities'},
            {'sequence': 8, 'name': 'Expectations and KPIs'},
            {'sequence': 9, 'name': 'Offer Letter'},
            {'sequence': 10, 'name': 'Deliverables 30-60-90 Checklists'},
            {'sequence': 11, 'name': 'Supervisor Review Checklist'},
            {'sequence': 12, 'name': 'Performance Review'},
        ]

        for item in default_checklist_items:
            self.env['hr.job.checklist.template'].create({
                'job_id': self.id,
                'name': item['name'],
                'sequence': item['sequence'],
            })

        return {
            'type': 'ir.actions.client',
            'tag': 'display_notification',
            'params': {
                'title': 'Checklist Templates Created',
                'message': f'{len(default_checklist_items)} default checklist templates have been added.',
                'type': 'success',
                'sticky': False,
            }
        }
